namespace SiteInspector.Models;

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteName { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
    public bool IsSynced { get; set; }
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<string> PhotoIds { get; set; } = new();
    public string Notes { get; set; } = string.Empty;
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public CheckStatus Status { get; set; } = CheckStatus.NotChecked;
    public string Note { get; set; } = string.Empty;
}

public enum CheckStatus
{
    NotChecked,
    Pass,
    Fail,
    NotApplicable
}

public class PhotoRecord
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string InspectionId { get; set; } = string.Empty;
    public string FileName { get; set; } = string.Empty;
    public string DataUrl { get; set; } = string.Empty;
    public DateTime CapturedAt { get; set; } = DateTime.UtcNow;
    public bool IsSynced { get; set; }
}

public class SyncStatus
{
    public int PendingInspections { get; set; }
    public int PendingPhotos { get; set; }
    public bool IsOnline { get; set; }
    public DateTime? LastSyncAttempt { get; set; }
}

namespace SiteInspector.Models;

public static class ChecklistTemplates
{
    public static List<ChecklistItem> GetStandardChecklist() => new()
    {
        // Fall Protection
        new() { Category = "Fall Protection", Description = "Guardrails installed on open edges" },
        new() { Category = "Fall Protection", Description = "Floor openings covered or guarded" },
