        new() { Category = "PPE", Description = "Appropriate footwear worn" },

        // Fire Safety
        new() { Category = "Fire Safety", Description = "Fire extinguishers accessible and inspected" },
        new() { Category = "Fire Safety", Description = "Hot work permits in place" },
