const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('inspections')) {
                database.createObjectStore('inspections', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('photos')) {
                database.createObjectStore('photos', { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbInterop = {
    saveInspection: async function (json) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readwrite');
        tx.objectStore('inspections').put(JSON.parse(json));
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getInspection: async function (id) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').get(id);
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllInspections: async function () {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteInspection: async function (id) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readwrite');
        tx.objectStore('inspections').delete(id);
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    savePhoto: async function (json) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readwrite');
        tx.objectStore('photos').put(JSON.parse(json));
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPhoto: async function (id) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').get(id);
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getPhotosForInspection: async function (inspectionId) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const filtered = (request.result || []).filter(p => p.inspectionId === inspectionId);
                resolve(JSON.stringify(filtered));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedInspections: async function () {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const unsynced = (request.result || []).filter(i => !i.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedPhotos: async function () {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const unsynced = (request.result || []).filter(p => !p.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityInterop = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public IndexedDbService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.saveInspection", json);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getInspection", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getAllInspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.deleteInspection", id);
    }

    public async Task SavePhotoAsync(PhotoRecord photo)
    {
        var json = JsonSerializer.Serialize(photo, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.savePhoto", json);
    }

    public async Task<PhotoRecord?> GetPhotoAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getPhoto", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<PhotoRecord>(json, JsonOptions);
    }

    public async Task<List<PhotoRecord>> GetPhotosForInspectionAsync(string inspectionId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getPhotosForInspection", inspectionId);
        return JsonSerializer.Deserialize<List<PhotoRecord>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getUnsyncedInspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<PhotoRecord>> GetUnsyncedPhotosAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getUnsyncedPhotos");
        return JsonSerializer.Deserialize<List<PhotoRecord>>(json, JsonOptions) ?? new();
    }
}

using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = new();

    public SyncService(IndexedDbService db, HttpClient http, IJSRuntime js)
    {
        _db = db;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
        CurrentStatus.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");

        // Check for pending items every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        CurrentStatus.IsOnline = isOnline;
        NotifyStatusChanged();

        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        try
        {
            var unsyncedInspections = await _db.GetUnsyncedInspectionsAsync();
            var unsyncedPhotos = await _db.GetUnsyncedPhotosAsync();

            CurrentStatus.PendingInspections = unsyncedInspections.Count;
            CurrentStatus.PendingPhotos = unsyncedPhotos.Count;
            CurrentStatus.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
            NotifyStatusChanged();

            if (!CurrentStatus.IsOnline) return;

            // Attempt to sync inspections
            foreach (var inspection in unsyncedInspections)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _db.SaveInspectionAsync(inspection);
                        CurrentStatus.PendingInspections--;
                        NotifyStatusChanged();
                    }
                }
                catch
                {
                    // Server unavailable — will retry later
                    break;
                }
            }

            // Attempt to sync photos
            foreach (var photo in unsyncedPhotos)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/photos", photo);
                    if (response.IsSuccessStatusCode)
                    {
                        photo.IsSynced = true;
                        await _db.SavePhotoAsync(photo);
                        CurrentStatus.PendingPhotos--;
                        NotifyStatusChanged();
                    }
                }
                catch
                {
                    break;
                }
            }

            CurrentStatus.LastSyncAttempt = DateTime.UtcNow;
            NotifyStatusChanged();
        }
        catch
        {
            // Silently handle — offline scenario
        }
    }

    private void NotifyStatusChanged() => OnSyncStatusChanged?.Invoke(CurrentStatus);

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _dotNetRef?.Dispose();
    }
}

