using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = new();

    public SyncService(IndexedDbService db, HttpClient http, IJSRuntime js)
    {
        _db = db;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
        CurrentStatus.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");

        // Check for pending items every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        CurrentStatus.IsOnline = isOnline;
        NotifyStatusChanged();

        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        try
        {
            var unsyncedInspections = await _db.GetUnsyncedInspectionsAsync();
            var unsyncedPhotos = await _db.GetUnsyncedPhotosAsync();

            CurrentStatus.PendingInspections = unsyncedInspections.Count;
            CurrentStatus.PendingPhotos = unsyncedPhotos.Count;
            CurrentStatus.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
            NotifyStatusChanged();

            if (!CurrentStatus.IsOnline) return;

            // Attempt to sync inspections
            foreach (var inspection in unsyncedInspections)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _db.SaveInspectionAsync(inspection);
                        CurrentStatus.PendingInspections--;
                        NotifyStatusChanged();
                    }
                }
                catch
                {
                    // Server unavailable — will retry later
                    break;
                }
            }

            // Attempt to sync photos
            foreach (var photo in unsyncedPhotos)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/photos", photo);
                    if (response.IsSuccessStatusCode)
                    {
                        photo.IsSynced = true;
                        await _db.SavePhotoAsync(photo);
                        CurrentStatus.PendingPhotos--;
                        NotifyStatusChanged();
                    }
                }
                catch
                {
                    break;
                }
            }

            CurrentStatus.LastSyncAttempt = DateTime.UtcNow;
            NotifyStatusChanged();
        }
        catch
        {
            // Silently handle — offline scenario
        }
    }

    private void NotifyStatusChanged() => OnSyncStatusChanged?.Invoke(CurrentStatus);

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _dotNetRef?.Dispose();
    }
}

