{"path": "/tmp/sv-48449e91d0864160978fe3677504484c/SiteInspector/wwwroot/js/indexedDb.js", "file_text": "const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('inspections')) {
                database.createObjectStore('inspections', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('photos')) {
                database.createObjectStore('photos', { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbInterop = {
    saveInspection: async function (json) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readwrite');
        tx.objectStore('inspections').put(JSON.parse(json));
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getInspection: async function (id) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').get(id);
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllInspections: async function () {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteInspection: async function (id) {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readwrite');
        tx.objectStore('inspections').delete(id);
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    savePhoto: async function (json) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readwrite');
        tx.objectStore('photos').put(JSON.parse(json));
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPhoto: async function (id) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').get(id);
        return new Promise((resolve, reject) => {
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getPhotosForInspection: async function (inspectionId) {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const filtered = (request.result || []).filter(p => p.inspectionId === inspectionId);
                resolve(JSON.stringify(filtered));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedInspections: async function () {
        const database = await openDb();
        const tx = database.transaction('inspections', 'readonly');
        const request = tx.objectStore('inspections').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const unsynced = (request.result || []).filter(i => !i.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedPhotos: async function () {
        const database = await openDb();
        const tx = database.transaction('photos', 'readonly');
        const request = tx.objectStore('photos').getAll();
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const unsynced = (request.result || []).filter(p => !p.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityInterop = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};
"}

