@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<button class="btn-primary-large" @onclick="StartNewInspection">
    ➕ New Inspection
</button>

<h2 class="section-title">Recent Inspections</h2>

@if (_inspections == null)
{
    <p class="loading">Loading...</p>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet.</p>
        <p>Tap <strong>New Inspection</strong> to get started.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header-row">
                    <span class="site-name">@inspection.SiteName</span>
                    <span class="sync-badge @(inspection.IsSynced ? "synced" : "pending")">
                        @(inspection.IsSynced ? "✓ Synced" : "⏳ Pending")
                    </span>
                </div>
                <div class="card-details">
                    <span>👷 @inspection.InspectorName</span>
                    <span>📅 @inspection.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                </div>
                <div class="card-progress">
                    @{ var total = inspection.ChecklistItems.Count;
                       var done = inspection.ChecklistItems.Count(c => c.Status != CheckStatus.NotChecked); }
                    <div class="progress-bar">
                        <div class="progress-fill" style="width: @(total > 0 ? (done * 100 / total) : 0)%"></div>
                    </div>
                    <span class="progress-text">@done / @total items</span>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Inspection>? _inspections;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspections = await Db.GetAllInspectionsAsync();
            StateHasChanged();
        }
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo("/inspection/new");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }
}

@page "/inspection/new"
@page "/inspection/{InspectionId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-header compact">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>@(_isNew ? "New Inspection" : "Edit Inspection")</h1>
</div>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <!-- Site Info Section -->
    @if (_currentView == InspectionView.Info)
    {
        <div class="form-section">
            <label>Site Name</label>
            <input type="text" class="form-input" @bind="_inspection.SiteName" 
                   @bind:event="oninput" placeholder="e.g., 123 Main St Tower" />

            <label>Inspector Name</label>
            <input type="text" class="form-input" @bind="_inspection.InspectorName" 
                   @bind:event="oninput" placeholder="Your name" />

            <label>Notes</label>
            <textarea class="form-textarea" @bind="_inspection.Notes" 
                      @bind:event="oninput" placeholder="General observations..." rows="4"></textarea>
        </div>

        <button class="btn-primary-large" @onclick="StartChecklist" disabled="@(string.IsNullOrWhiteSpace(_inspection.SiteName))">
            ▶️ Start Checklist
        </button>
    }

    <!-- Checklist Section -->
    @if (_currentView == InspectionView.Checklist)
    {
        <div class="checklist-nav">
            @foreach (var category in _categories)
            {
                <button class="category-tab @(category == _activeCategory ? "active" : "")"
                        @onclick="() => SetCategory(category)">
                    @category
                    @{ var catItems = _inspection.ChecklistItems.Where(c => c.Category == category).ToList();
                       var catDone = catItems.Count(c => c.Status != CheckStatus.NotChecked); }
                    <span class="cat-count">@catDone/@catItems.Count</span>
                </button>
            }
        </div>

        <div class="checklist-items">
            @foreach (var item in _inspection.ChecklistItems.Where(c => c.Category == _activeCategory))
            {
                <div class="checklist-item @item.Status.ToString().ToLower()">
                    <p class="item-description">@item.Description</p>
                    <div class="status-buttons">
                        <button class="status-btn pass @(item.Status == CheckStatus.Pass ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.Pass)">✓</button>
                        <button class="status-btn fail @(item.Status == CheckStatus.Fail ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.Fail)">✗</button>
                        <button class="status-btn na @(item.Status == CheckStatus.NotApplicable ? "selected" : "")"
                                @onclick="() => SetStatus(item, CheckStatus.NotApplicable)">N/A</button>
                    </div>
                    @if (item.Status == CheckStatus.Fail)
                    {
                        <input type="text" class="item-note" @bind="item.Note" @bind:event="oninput"
                               placeholder="Note about failure..." />
                    }
                </div>
            }
        </div>

        <div class="checklist-footer">
            <button class="btn-secondary" @onclick="() => _currentView = InspectionView.Info">← Info</button>
            <button class="btn-primary" @onclick="GoToPhotos">Photos →</button>
        </div>
    }

    <!-- Photos Section -->
    @if (_currentView == InspectionView.Photos)
    {
        <div class="photo-section">
            <label class="photo-capture-btn">
                📷 Take / Add Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" class="hidden-input" />
            </label>

            @if (_photos.Any())
            {
                <div class="photo-grid">
                    @foreach (var photo in _photos)
                    {
                        <div class="photo-thumb">
                            <img src="@photo.DataUrl" alt="@photo.FileName" />
                        </div>
                    }
                </div>
            }
            else
            {
                <p class="empty-state">No photos yet. Tap above to capture.</p>
            }
        </div>

        <div class="checklist-footer">
            <button class="btn-secondary" @onclick="() => _currentView = InspectionView.Checklist">← Checklist</button>
            <button class="btn-primary-large" @onclick="SaveAndFinish">💾 Save Inspection</button>
        </div>
    }
}

@code {
    [Parameter] public string? InspectionId { get; set; }

    private Inspection? _inspection;
    private bool _isNew;
    private InspectionView _currentView = InspectionView.Info;
    private List<string> _categories = new();
    private string _activeCategory = string.Empty;
    private List<PhotoRecord> _photos = new();

    private enum InspectionView { Info, Checklist, Photos }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        if (InspectionId == "new" || string.IsNullOrEmpty(InspectionId))
        {
            _isNew = true;
            _inspection = new Inspection
            {
                ChecklistItems = ChecklistTemplates.GetStandardChecklist()
            };
        }
        else
        {
            _inspection = await Db.GetInspectionAsync(InspectionId);
            if (_inspection == null)
            {
                Nav.NavigateTo("/");
                return;
            }
            _photos = await Db.GetPhotosForInspectionAsync(InspectionId);
        }

        _categories = _inspection!.ChecklistItems.Select(c => c.Category).Distinct().ToList();
        if (_categories.Any()) _activeCategory = _categories.First();
        StateHasChanged();
    }

    private void SetCategory(string category) => _activeCategory = category;

    private async Task SetStatus(ChecklistItem item, CheckStatus status)
    {
        item.Status = status;
        // Auto-save after each tap for resilience
        await AutoSave();
    }

    private void StartChecklist() => _currentView = InspectionView.Checklist;

    private void GoToPhotos() => _currentView = InspectionView.Photos;

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB

            var buffer = new byte[file.Size];
            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);
            var dataUrl = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

            var photo = new PhotoRecord
            {
                InspectionId = _inspection!.Id,
                FileName = file.Name,
                DataUrl = dataUrl
            };

            await Db.SavePhotoAsync(photo);
            _photos.Add(photo);
            _inspection.PhotoIds.Add(photo.Id);
        }
        await AutoSave();
    }

    private async Task AutoSave()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Db.SaveInspectionAsync(_inspection);
    }

    private async Task SaveAndFinish()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Db.SaveInspectionAsync(_inspection);
        Nav.NavigateTo("/");
    }

    private async Task GoBack()
    {
        if (_inspection != null && !string.IsNullOrWhiteSpace(_inspection.SiteName))
        {
            await AutoSave();
        }
        Nav.NavigateTo("/");
    }
}

@using SiteInspector.Models
@using SiteInspector.Services
@inject SyncService Sync
@implements IDisposable

<div class="sync-bar @(_status.IsOnline ? "online" : "offline")">
    <span class="connectivity-dot"></span>
    <span>@(_status.IsOnline ? "Online" : "Offline")</span>
    @if (_status.PendingInspections > 0 || _status.PendingPhotos > 0)
    {
        <span class="pending-count">
            @(_status.PendingInspections + _status.PendingPhotos) pending
        </span>
    }
</div>

@code {
    private SyncStatus _status = new();

    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += HandleStatusChanged;
        _status = Sync.CurrentStatus;
    }

    private void HandleStatusChanged(SyncStatus status)
    {
        _status = status;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= HandleStatusChanged;
    }
}

