@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<button class="btn-primary-large" @onclick="StartNewInspection">
    ➕ New Inspection
</button>

<h2 class="section-title">Recent Inspections</h2>

@if (_inspections == null)
{
    <p class="loading">Loading...</p>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet.</p>
        <p>Tap <strong>New Inspection</strong> to get started.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header-row">
                    <span class="site-name">@inspection.SiteName</span>
                    <span class="sync-badge @(inspection.IsSynced ? "synced" : "pending")">
                        @(inspection.IsSynced ? "✓ Synced" : "⏳ Pending")
                    </span>
                </div>
                <div class="card-details">
                    <span>👷 @inspection.InspectorName</span>
                    <span>📅 @inspection.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                </div>
                <div class="card-progress">
                    @{ var total = inspection.ChecklistItems.Count;
                       var done = inspection.ChecklistItems.Count(c => c.Status != CheckStatus.NotChecked); }
                    <div class="progress-bar">
                        <div class="progress-fill" style="width: @(total > 0 ? (done * 100 / total) : 0)%"></div>
                    </div>
                    <span class="progress-text">@done / @total items</span>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Inspection>? _inspections;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspections = await Db.GetAllInspectionsAsync();
            StateHasChanged();
        }
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo("/inspection/new");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }
}

